// === Engineered numeric features ===
double amount = ctx.amount instanceof Number ? ((Number)ctx.amount).doubleValue() : 0.0;
double fee = ctx.fee instanceof Number ? ((Number)ctx.fee).doubleValue() : 0.0;
double lat = ctx.latitude instanceof Number ? ((Number)ctx.latitude).doubleValue() : Double.NaN;
double lon = ctx.longitude instanceof Number ? ((Number)ctx.longitude).doubleValue() : Double.NaN;

ctx.amount = amount;
ctx.fee = fee;
ctx.latitude = Double.isNaN(lat) ? params.med_latitude : lat;
ctx.longitude = Double.isNaN(lon) ? params.med_longitude : lon;

ctx.log_amount = Math.log1p(Math.max(amount, 0.0));
ctx.log_fee = Math.log1p(Math.max(fee, 0.0));
ctx.fee_ratio = amount == 0.0 ? 0.0 : (fee / amount);

ctx.has_geo = ctx.containsKey('latitude') && ctx.latitude != null ? 1 : 0;
ctx.has_device = ctx.containsKey('deviceId') && ctx.deviceId != null ? 1 : 0;
ctx.has_ip = ctx.containsKey('ipAddress') && ctx.ipAddress != null ? 1 : 0;

String srcBic = ctx.sourceBic != null ? ctx.sourceBic.toString() : "";
String dstBic = ctx.destinationBic != null ? ctx.destinationBic.toString() : "";
ctx.cross_bank = srcBic.equals(dstBic) ? 0 : 1;

String srcCC = ctx.sourceCountryCode != null ? ctx.sourceCountryCode.toString() : "";
String dstCC = ctx.destinationCountryCode != null ? ctx.destinationCountryCode.toString() : "";
ctx.cross_country = (!srcCC.equals(dstCC) && !srcCC.isEmpty() && !dstCC.isEmpty()) ? 1 : 0;

// === Numeric scaling: (val - center) / scale, with median imputation ===
double v_amount = ctx.amount instanceof Number ? ((Number)ctx.amount).doubleValue() : 15000.0;
ctx['num__amount'] = (v_amount - 15000.0) / 48000.0;
double v_fee = ctx.fee instanceof Number ? ((Number)ctx.fee).doubleValue() : 0.0;
ctx['num__fee'] = (v_fee - 0.0) / 1000.0;
double v_latitude = ctx.latitude instanceof Number ? ((Number)ctx.latitude).doubleValue() : -6.1617169;
ctx['num__latitude'] = (v_latitude - -6.1617169) / 1.0;
double v_longitude = ctx.longitude instanceof Number ? ((Number)ctx.longitude).doubleValue() : 106.6643946;
ctx['num__longitude'] = (v_longitude - 106.6643946) / 1.0;
double v_log_amount = ctx.log_amount instanceof Number ? ((Number)ctx.log_amount).doubleValue() : 9.61587214452889;
ctx['num__log_amount'] = (v_log_amount - 9.61587214452889) / 3.2183959496265526;
double v_log_fee = ctx.log_fee instanceof Number ? ((Number)ctx.log_fee).doubleValue() : 0.0;
ctx['num__log_fee'] = (v_log_fee - 0.0) / 6.90875477931522;
double v_fee_ratio = ctx.fee_ratio instanceof Number ? ((Number)ctx.fee_ratio).doubleValue() : 0.0;
ctx['num__fee_ratio'] = (v_fee_ratio - 0.0) / 0.5;
double v_has_geo = ctx.has_geo instanceof Number ? ((Number)ctx.has_geo).doubleValue() : 0.0;
ctx['num__has_geo'] = (v_has_geo - 0.0) / 1.0;
double v_has_device = ctx.has_device instanceof Number ? ((Number)ctx.has_device).doubleValue() : 0.0;
ctx['num__has_device'] = (v_has_device - 0.0) / 1.0;
double v_has_ip = ctx.has_ip instanceof Number ? ((Number)ctx.has_ip).doubleValue() : 0.0;
ctx['num__has_ip'] = (v_has_ip - 0.0) / 1.0;
double v_cross_bank = ctx.cross_bank instanceof Number ? ((Number)ctx.cross_bank).doubleValue() : 1.0;
ctx['num__cross_bank'] = (v_cross_bank - 1.0) / 1.0;
double v_cross_country = ctx.cross_country instanceof Number ? ((Number)ctx.cross_country).doubleValue() : 0.0;
ctx['num__cross_country'] = (v_cross_country - 0.0) / 1.0;
double v_amt_sum_2min = ctx.amt_sum_2min instanceof Number ? ((Number)ctx.amt_sum_2min).doubleValue() : 2000.0;
ctx['num__amt_sum_2min'] = (v_amt_sum_2min - 2000.0) / 44750.0;
