double v_amt_sum_1d = ctx.amt_sum_1d instanceof Number ? ((Number)ctx.amt_sum_1d).doubleValue() : 91000.255;
ctx['num__amt_sum_1d'] = (v_amt_sum_1d - 91000.255) / 780000.0;
double v_tx_count_5min = ctx.tx_count_5min instanceof Number ? ((Number)ctx.tx_count_5min).doubleValue() : 1.0;
